<# RayStudio Workplace Assessment V14 - DE-CH HTML report #>
[CmdletBinding()]
param([switch]$NoOpen,[ValidateSet('DE-CH','EN')][string]$Lang='DE-CH')
$ErrorActionPreference='Continue'
$Started=Get-Date
$Root=Split-Path -Parent $PSScriptRoot
$OutDir=Join-Path $Root 'output'
New-Item -ItemType Directory -Path $OutDir -Force | Out-Null
$Computer=$env:COMPUTERNAME
$Stamp=Get-Date -Format 'yyyy-MM-dd_HH-mm-ss'
$JsonPath=Join-Path $OutDir "Assessment_${Computer}_${Stamp}.json"
$HtmlPath=Join-Path $OutDir "Assessment_${Computer}_${Stamp}.html"
$Utf8NoBom=[System.Text.UTF8Encoding]::new($false)
function IsAdmin{try{return ([Security.Principal.WindowsPrincipal][Security.Principal.WindowsIdentity]::GetCurrent()).IsInRole([Security.Principal.WindowsBuiltinRole]::Administrator)}catch{return $false}}
function Finding($cat,$check,$status,$score,$max,$eKey,$eArgs,$risk,$rec,$details=@()){
 [pscustomobject]@{categoryKey=$cat;checkKey=$check;statusKey=$status;score=$score;maxScore=$max;scored=($max -gt 0);evidenceKey=$eKey;evidenceArgs=$eArgs;riskKey=$risk;recommendationKey=$rec;details=$details}
}
function PendingFinding{
 $wu=Test-Path 'HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\WindowsUpdate\Auto Update\RebootRequired'
 $cbs=Test-Path 'HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Component Based Servicing\RebootPending'
 $pfr=@();try{$raw=(Get-ItemProperty 'HKLM:\SYSTEM\CurrentControlSet\Control\Session Manager' -Name PendingFileRenameOperations -ErrorAction Stop).PendingFileRenameOperations;if($raw){$pfr=@($raw|?{$_ -and $_.ToString().Trim() -ne ''})}}catch{}
 $tempOnly=$false;$hasApp=$false;$hasSystem=$false;$app=@();$sys=@();$tmp=@();$other=@()
 if($pfr.Count -gt 0){$tempOnly=$true;foreach($i in $pfr){$s=[string]$i;if($s -match '(?i)\\Windows\\Temp\\DEL[0-9A-F]+\.tmp$'){$tmp+=$s}else{$tempOnly=$false};if($s -match '(?i)\\Windows\\System32\\drivers\\|\\DriverStore\\|\\System32\\.*\.sys$'){$hasSystem=$true;$sys+=$s}elseif($s -match '(?i)OneDrive|Teams|MSEdge|Microsoft Edge|Chrome|Firefox|GamingServices|gamingservices|Office|ClickToRun|Adobe|Zoom|Webex'){$hasApp=$true;$app+=$s}elseif($s -notmatch '(?i)\\Windows\\Temp\\DEL[0-9A-F]+\.tmp$'){$other+=$s}}}
 $st='ok';$sc=15;$e='pendingNone';$r='riskNone';$rec='recNone';$class='none'
 if($wu -or $cbs){$st='critical';$sc=0;$e='pendingWindows';$r='riskWindowsPending';$rec='recRestartNow';$class='windows'}elseif($hasSystem){$st='warning';$sc=5;$e='pendingSystem';$r='riskSystemPending';$rec='recRestartSoon';$class='system'}elseif($hasApp){$st='warning';$sc=10;$e='pendingApp';$r='riskAppPending';$rec='recRestartConvenient';$class='app'}elseif($pfr.Count -gt 0 -and $tempOnly){$st='info';$sc=15;$e='pendingTemp';$r='riskTempOnly';$rec='recNoImmediateAction';$class='temp'}elseif($pfr.Count -gt 0){$st='warning';$sc=10;$e='pendingGeneric';$r='riskGenericPending';$rec='recReviewRestart';$class='generic'}
 $d=@("classification=$class","WU=$wu","CBS=$cbs","PendingRename=$($pfr.Count -gt 0)","PendingRenameCount=$($pfr.Count)");if($app){$d+='';$d+='Application files:';$d+=$app};if($sys){$d+='';$d+='System/driver files:';$d+=$sys};if($tmp){$d+='';$d+='Temporary cleanup files:';$d+=$tmp};if($other){$d+='';$d+='Other entries:';$d+=$other}
 Finding 'health' 'rebootStatus' $st $sc 15 $e @{count=$pfr.Count;wu=$wu;cbs=$cbs} $r $rec $d
}
function UptimeFinding{try{$os=Get-CimInstance Win32_OperatingSystem -ErrorAction Stop;$last=$os.LastBootUpTime;$days=[math]::Round(((Get-Date)-$last).TotalDays,1);$st='ok';$sc=10;$r='riskUptimeOk';$rec='recNone';if($days -gt 30){$st='warning';$sc=5;$r='riskLongUptime';$rec='recRegularRestart'};Finding 'health' 'uptime' $st $sc 10 'uptimeEvidence' @{days=$days;lastBoot=$last.ToString('dd.MM.yyyy HH:mm:ss')} $r $rec}catch{Finding 'health' 'uptime' 'info' 0 0 'queryUnavailable' @{} 'notScored' 'checkManually'}}
function StorageFinding{try{$c=Get-CimInstance Win32_LogicalDisk -Filter "DeviceID='C:'" -ErrorAction Stop}catch{$c=$null};if(-not $c -or -not $c.Size){return Finding 'storage' 'systemDrive' 'info' 0 0 'queryUnavailable' @{} 'notScored' 'checkManually'};$pct=[math]::Round(($c.FreeSpace/$c.Size)*100,1);$free=[math]::Round($c.FreeSpace/1GB,1);$size=[math]::Round($c.Size/1GB,1);$st='ok';$sc=15;$r='riskStorageOk';$rec='recNone';if($pct -lt 10){$st='critical';$sc=3;$r='riskStorageCritical';$rec='recFreeSpace'}elseif($pct -lt 20){$st='warning';$sc=10;$r='riskStorageWarning';$rec='recStorageCleanup'};Finding 'storage' 'systemDrive' $st $sc 15 'storageEvidence' @{freeGb=$free;sizeGb=$size;freePct=$pct} $r $rec}
function AdminFinding{$m=@();try{$m=@(Get-LocalGroupMember -Group 'Administrators' -ErrorAction Stop|select -ExpandProperty Name)}catch{$m=@('Query failed')};$cnt=@($m|?{$_ -ne 'Query failed'}).Count;$st='ok';$sc=10;$r='riskLocalAdminsOk';$rec='recNone';if($cnt -gt 6){$st='warning';$sc=4;$r='riskManyLocalAdmins';$rec='recLocalAdminsReduce'}elseif($cnt -gt 3){$st='warning';$sc=7;$r='riskSomeLocalAdmins';$rec='recLocalAdminsReview'};Finding 'management' 'localAdmins' $st $sc 10 'localAdminsEvidence' @{count=$cnt} $r $rec $m}
function RemoteFinding{$pat=@('TeamViewer','AnyDesk','RealVNC','VNC','UltraVNC','RustDesk','Splashtop','ScreenConnect','ConnectWise','LogMeIn');$hits=@();foreach($root in @('HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\Uninstall\*','HKLM:\SOFTWARE\WOW6432Node\Microsoft\Windows\CurrentVersion\Uninstall\*')){try{Get-ItemProperty $root -ErrorAction SilentlyContinue|%{$dn=$_.DisplayName;if($dn){foreach($p in $pat){if($dn -match [regex]::Escape($p)){$hits+=$dn}}}}}catch{}};$hits=@($hits|sort -Unique);$st='ok';$sc=10;$e='remoteToolsNone';$r='riskRemoteToolsOk';$rec='recNone';if($hits.Count -gt 0){$st='warning';$sc=4;$e='remoteToolsFound';$r='riskRemoteTools';$rec='recRemoteTools'};Finding 'management' 'remoteTools' $st $sc 10 $e @{list=($hits -join '; ')} $r $rec $hits}
function StartupFinding{$sus=@();foreach($rk in @('HKLM:\Software\Microsoft\Windows\CurrentVersion\Run','HKCU:\Software\Microsoft\Windows\CurrentVersion\Run')){try{$p=Get-ItemProperty $rk -ErrorAction SilentlyContinue;if($p){$p.PSObject.Properties|?{$_.Name -notmatch '^PS'}|%{$v=[string]$_.Value;if($v -match '(?i)AppData\\Local\\Temp|\\Temp\\|powershell.+-enc|wscript|cscript|rundll32.+AppData'){$sus+="$($_.Name)=$v"}}}}catch{}};$st='ok';$sc=10;$r='riskStartupOk';$rec='recNone';if($sus.Count -ge 3){$st='warning';$sc=5;$r='riskStartupSuspicious';$rec='recStartupReview'}elseif($sus.Count -gt 0){$st='info';$sc=8;$r='riskStartupSingle';$rec='recStartupReview'};Finding 'security' 'startupCheck' $st $sc 10 'startupEvidence' @{count=$sus.Count} $r $rec $sus}
function SecureBootFinding{try{$sb=Confirm-SecureBootUEFI -ErrorAction Stop;if($sb){Finding 'security' 'secureBoot' 'ok' 10 10 'secureBootOn' @{} 'riskSecureBootOk' 'recNone'}else{Finding 'security' 'secureBoot' 'warning' 5 10 'secureBootOff' @{} 'riskSecureBootOff' 'recSecureBoot'}}catch{Finding 'security' 'secureBoot' 'info' 0 0 'queryUnavailable' @{} 'notScored' 'checkManually'}}
function TpmFinding{try{$t=Get-CimInstance -Namespace 'root\cimv2\Security\MicrosoftTpm' -ClassName Win32_Tpm -ErrorAction Stop}catch{return Finding 'security' 'tpm' 'info' 0 0 'queryUnavailable' @{} 'notScored' 'checkManually'};if(-not $t){return Finding 'security' 'tpm' 'critical' 0 10 'tpmMissing' @{} 'riskTpmMissing' 'recTpmMissing'};$spec=[string]$t.SpecVersion;$maj=($spec -split ',')[0].Trim();$en=[bool]$t.IsEnabled_InitialValue;$ac=[bool]$t.IsActivated_InitialValue;$d=@("SpecVersion=$spec","Manufacturer=$($t.ManufacturerIdTxt)","ManufacturerVersion=$($t.ManufacturerVersion)","Enabled=$en","Activated=$ac","Owned=$($t.IsOwned_InitialValue)");if($maj -notlike '2.*'){Finding 'security' 'tpm' 'critical' 0 10 'tpmOld' @{specVersion=$maj} 'riskTpmOld' 'recTpmUpgrade' $d}elseif(-not($en -and $ac)){Finding 'security' 'tpm' 'warning' 5 10 'tpmDisabled' @{specVersion=$maj;enabled=$en;activated=$ac} 'riskTpmDisabled' 'recTpmEnable' $d}else{Finding 'security' 'tpm' 'ok' 10 10 'tpmOk' @{specVersion=$maj} 'riskTpmOk' 'recNone' $d}}
function WindowsEditionFinding{try{$os=Get-CimInstance Win32_OperatingSystem -ErrorAction Stop;$sku=$os.OperatingSystemSKU;$cap=$os.Caption}catch{return Finding 'management' 'windowsEdition' 'info' 0 0 'queryUnavailable' @{} 'notScored' 'checkManually'};$bizSkus=@(4,27,48,121,125,161,162);$isBiz=$bizSkus -contains $sku;if(-not $isBiz){return Finding 'management' 'windowsEdition' 'critical' 0 10 'editionHome' @{caption=$cap;sku=$sku} 'riskEditionHome' 'recEditionUpgrade' @("Caption=$cap","SKU=$sku")};$lic=$null;try{$lic=@(Get-CimInstance -Query "SELECT * FROM SoftwareLicensingProduct WHERE PartialProductKey IS NOT NULL AND Name LIKE 'Windows%'" -ErrorAction Stop|?{$_.PartialProductKey})}catch{};if(-not $lic -or $lic.Count -eq 0){return Finding 'management' 'windowsEdition' 'info' 0 0 'queryUnavailable' @{caption=$cap} 'notScored' 'checkManually' @("Caption=$cap","SKU=$sku","LicenseQuery=empty_or_failed")};$best=$lic|?{$_.LicenseStatus -eq 1}|select -First 1;if(-not $best){$best=$lic|select -First 1};$ls=[int]$best.LicenseStatus;$lsMap=@{0='Unlicensed';1='Licensed';2='OOBGrace';3='OOTGrace';4='NonGenuineGrace';5='Notification';6='ExtendedGrace'};$lsText=$lsMap[$ls];$d=@("Caption=$cap","SKU=$sku","LicenseStatus=$ls ($lsText)","PartialProductKey=...$($best.PartialProductKey)","Name=$($best.Name)");if($ls -eq 1){Finding 'management' 'windowsEdition' 'ok' 10 10 'editionOkLicensed' @{caption=$cap;licenseStatus=$lsText} 'riskEditionOk' 'recNone' $d}elseif($ls -eq 0){Finding 'management' 'windowsEdition' 'critical' 0 10 'editionUnlicensed' @{caption=$cap;licenseStatus=$lsText} 'riskEditionUnlicensed' 'recLicenseActivate' $d}else{Finding 'management' 'windowsEdition' 'warning' 6 10 'editionOkGrace' @{caption=$cap;licenseStatus=$lsText} 'riskEditionGrace' 'recLicenseActivate' $d}}
function BatteryFinding{try{$b=@(Get-CimInstance Win32_Battery -ErrorAction Stop)}catch{return Finding 'health' 'batteryHealth' 'info' 0 0 'queryUnavailable' @{} 'notScored' 'checkManually'};if(-not $b -or $b.Count -eq 0){return Finding 'health' 'batteryHealth' 'info' 0 0 'batteryNotPresent' @{} 'notScored' 'recNone'};$bs=$b[0].BatteryStatus;$pct=$b[0].EstimatedChargeRemaining;$design=$null;$full=$null;try{$design=(Get-CimInstance -Namespace 'root\wmi' -ClassName BatteryStaticData -ErrorAction Stop|select -First 1).DesignedCapacity;$full=(Get-CimInstance -Namespace 'root\wmi' -ClassName BatteryFullChargedCapacity -ErrorAction Stop|select -First 1).FullChargedCapacity}catch{};$d=@("BatteryStatus=$bs","EstimatedChargeRemaining=$pct%","DesignedCapacity=$design","FullChargedCapacity=$full");if(-not $design -or -not $full -or $design -eq 0){return Finding 'health' 'batteryHealth' 'info' 0 0 'batteryWearUnavailable' @{chargePct=$pct} 'notScored' 'checkManually' $d};$wear=[math]::Round((1-($full/$design))*100,1);$st='ok';$sc=10;$e='batteryHealthy';$r='riskBatteryOk';$rec='recNone';if($wear -gt 40){$st='critical';$sc=0;$e='batteryWornCritical';$r='riskBatteryWornCritical';$rec='recBatteryReplace'}elseif($wear -gt 20){$st='warning';$sc=5;$e='batteryWornWarning';$r='riskBatteryWornWarning';$rec='recBatteryMonitor'};Finding 'health' 'batteryHealth' $st $sc 10 $e @{wearPct=$wear;chargePct=$pct} $r $rec $d}
$findings=@();$findings+=PendingFinding;$findings+=UptimeFinding;$findings+=StorageFinding;$findings+=AdminFinding;$findings+=RemoteFinding;$findings+=StartupFinding;$findings+=SecureBootFinding;$findings+=TpmFinding;$findings+=WindowsEditionFinding;$findings+=BatteryFinding
$scored=@($findings|?{$_.maxScore -gt 0});$totalScore=($scored|measure score -Sum).Sum;$totalMax=($scored|measure maxScore -Sum).Sum;$overall=if($totalMax -gt 0){[math]::Round(($totalScore/$totalMax)*100)}else{0}
$cats=[ordered]@{};foreach($cat in @('security','health','storage','management')){$f=@($scored|?{$_.categoryKey -eq $cat});if($f.Count){$s=($f|measure score -Sum).Sum;$m=($f|measure maxScore -Sum).Sum;$cats[$cat]=[pscustomobject]@{score=$s;max=$m;percent=[math]::Round(($s/$m)*100);count=$f.Count}}}
$payload=[pscustomobject]@{version='14';computer=$Computer;user=$env:USERNAME;admin=(IsAdmin);started=$Started.ToString('s');completed=(Get-Date).ToString('s');lang=$Lang;scoring=[pscustomobject]@{score=$totalScore;max=$totalMax;percent=$overall;categories=$cats};findings=$findings}
$json=$payload|ConvertTo-Json -Depth 12;[IO.File]::WriteAllText($JsonPath,$json,$Utf8NoBom);$b64=[Convert]::ToBase64String([Text.Encoding]::UTF8.GetBytes($json))
$html=@'
<!doctype html><html lang="de-CH"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>RayStudio Workplace Assessment</title><style>:root{--bg:#071120;--panel:#111c2e;--line:#26364f;--text:#eef5ff;--muted:#adc0dd;--blue:#2f6df6;--green:#55d66b;--yellow:#f6ad2f;--red:#ef5350;--info:#38bdf8;--orange:#ffb020}*{box-sizing:border-box}body{margin:0;background:#071120;color:var(--text);font-family:Segoe UI,Arial,sans-serif}.wrap{max-width:1460px;margin:0 auto;padding:28px}.top{display:flex;gap:18px;align-items:flex-start}.brand{font-size:12px;color:#77aaff;font-weight:800;letter-spacing:.8px;text-transform:uppercase}.title{font-size:30px;font-weight:850;margin-top:4px}.meta{font-size:13px;color:var(--muted);margin-top:4px}.scoreBox{margin-left:auto;text-align:right;display:flex;align-items:center;gap:14px}.score{font-size:58px;font-weight:900}.overallLabel{font-size:15px;border:1px solid var(--line);border-radius:14px;padding:8px 12px;background:#0b1526;color:var(--muted);font-weight:800}.btn{border:0;border-radius:10px;background:var(--blue);color:white;padding:10px 14px;font-size:13px;font-weight:800;cursor:pointer}.btn.secondary{background:#23324a}.cards{display:grid;grid-template-columns:repeat(5,minmax(180px,1fr));gap:14px;margin:24px 0}.card{border:1px solid var(--line);border-radius:14px;background:var(--panel);padding:20px;min-height:122px}.donut{width:86px;height:86px;border-radius:50%;display:grid;place-items:center;margin:0 auto 12px}.donutInner{width:58px;height:58px;border-radius:50%;background:#0d1728;display:grid;place-items:center;font-weight:900;font-size:18px}.card h3{text-align:center;margin:5px 0;font-size:15px}.section{border:1px solid var(--line);border-radius:16px;background:var(--panel);padding:20px;margin-top:20px}.hint{font-size:13px;color:var(--muted);margin-bottom:14px}.tabs{display:flex;gap:8px;flex-wrap:wrap;margin:10px 0 14px}.tab{border:1px solid var(--line);background:#142036;color:var(--text);border-radius:9px;padding:9px 13px;font-weight:800;cursor:pointer}.tab.active{background:#dcecff;color:#071120}.tools{display:flex;gap:10px;margin-bottom:12px}.search{flex:1;border:1px solid var(--line);border-radius:10px;background:#0a1424;color:var(--text);padding:12px}table{width:100%;border-collapse:collapse;font-size:13px}th,td{padding:11px 10px;border-bottom:1px solid #24344d;text-align:left;vertical-align:top}th{color:#dcecff;background:#0b1526;position:sticky;top:0}.row{cursor:pointer}.row:hover{background:#17243a}.row.selected{background:#2563eb!important;color:#fff}.row.selected td{color:#fff}.badge{display:inline-block;border-radius:999px;padding:5px 10px;font-size:12px;font-weight:900;color:#071120}.ok{background:var(--green)}.warning{background:var(--yellow)}.critical{background:var(--red);color:#fff}.info{background:var(--info)}.details{display:none;background:#0a1424}.details.open{display:table-row}.pre{white-space:pre-wrap;font-family:Consolas,monospace;color:#dcecff}.summary{border-left:4px solid var(--orange);padding:8px 0 8px 14px;margin:8px 0 14px;color:#dcecff}.footer{margin-top:18px;color:var(--muted);font-size:12px;text-align:right}.error{display:none;background:#451414;border:1px solid #8a2c2c;color:#ffdede;border-radius:12px;padding:14px;margin:14px 0}@media(max-width:1100px){.cards{grid-template-columns:1fr 1fr}.top{flex-wrap:wrap}.scoreBox{margin-left:0}.tools{flex-wrap:wrap}.search{min-width:100%}}@media print{.tabs,.tools,.btn{display:none}body{background:white;color:black}.section,.card{background:white;color:black;border-color:#aaa}.meta,.hint,.footer{color:#333}th,td{color:black;border-color:#ddd}.badge{color:black}.donutInner{background:white}}</style></head><body><div class="wrap"><div class="top"><div><div class="brand">RAYSTUDIO WORKPLACE ASSESSMENT</div><div class="title" id="title"></div><div class="meta" id="meta"></div></div><div class="scoreBox"><div class="score" id="score">--%</div><div class="overallLabel" id="overallLabel"></div><button class="btn" onclick="window.print()" id="printBtn"></button></div></div><div id="err" class="error"></div><div class="cards" id="cards"></div><div class="section"><h2 id="sectionTitle"></h2><div class="hint" id="hint"></div><div class="tabs" id="tabs"></div><div class="tools"><input class="search" id="q" oninput="renderTable()"><button class="btn secondary" onclick="expandAll()" id="expandBtn"></button><button class="btn secondary" onclick="collapseAll()" id="collapseBtn"></button><button class="btn" onclick="downloadJson()" id="jsonBtn"></button></div><div style="overflow:auto;max-height:700px"><table><thead><tr><th id="thStatus"></th><th id="thCategory"></th><th id="thCheck"></th><th id="thScore"></th><th id="thEvidence"></th><th id="thRisk"></th><th id="thRecommendation"></th></tr></thead><tbody id="tbody"></tbody></table></div></div><div class="footer" id="footer"></div></div><script>
