function tr(k,a={}){let s=T[k]||k;for(const [x,y] of Object.entries(a||{}))s=s.replaceAll('{'+x+'}',String(y));return s}function decode(){const bin=atob(DATA_B64);const bytes=new Uint8Array([...bin].map(c=>c.charCodeAt(0)));return JSON.parse(new TextDecoder('utf-8').decode(bytes))}function esc(v){return String(v??'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]))}function pctColor(p){return p>=90?'var(--green)':p>=70?'var(--yellow)':'var(--red)'}function textOf(f,w){return w==='evidence'?tr(f.evidenceKey,f.evidenceArgs):w==='risk'?tr(f.riskKey):tr(f.recommendationKey)}function init(){data=decode();title.textContent=T.title;printBtn.textContent=T.print;overallLabel.textContent=T.overall;sectionTitle.textContent=T.section;hint.textContent=T.hint;q.placeholder=T.search;expandBtn.textContent=T.expand;collapseBtn.textContent=T.collapse;jsonBtn.textContent=T.json;thStatus.textContent=T.status;thCategory.textContent=T.category;thCheck.textContent=T.check;thScore.textContent=T.score;thEvidence.textContent=T.evidence;thRisk.textContent=T.risk;thRecommendation.textContent=T.recommendation;meta.textContent=`${data.user} @ ${data.computer} | ${data.completed} | ${T.admin}: ${data.admin?T.yes:T.no} | ${T.language}: ${data.lang}`;footer.textContent=`Assessment Engine ${data.version}.0 | ${data.computer} | ${data.completed}`;score.textContent=data.scoring.percent+'%';renderCards();renderTabs();renderTable()}function card(n,p){return `<div class="card"><div class="donut" style="background:conic-gradient(${pctColor(p)} ${p}%,#25324a 0)"><div class="donutInner">${p}%</div></div><h3>${esc(n)}</h3></div>`}function renderCards(){cards.innerHTML='';for(const [k,v] of Object.entries(data.scoring.categories||{}))cards.innerHTML+=card(tr(k),v.percent);cards.innerHTML+=card(T.overall,data.scoring.percent)}function renderTabs(){const vals=['all','critical','warning','info','ok'];tabs.innerHTML='';for(const t of vals){const b=document.createElement('button');b.className='tab'+(filter===t?' active':'');b.textContent=t==='all'?T.all:tr(t);b.onclick=()=>{filter=t;renderTabs();renderTable()};tabs.appendChild(b)}}function impact(f){return (f.maxScore||0)-(f.score||0)}function match(f,qv){if(!qv)return true;return [tr(f.categoryKey),tr(f.checkKey),tr(f.statusKey),textOf(f,'evidence'),textOf(f,'risk'),textOf(f,'recommendation'),(f.details||[]).join(' ')].join(' ').toLowerCase().includes(qv.toLowerCase())}function renderTable(){tbody.innerHTML='';const qv=q.value;for(const f of (data.findings||[]).filter(x=>x.maxScore>0).sort((a,b)=>impact(b)-impact(a))){if(filter!=='all'&&f.statusKey!==filter)continue;if(!match(f,qv))continue;const id='d'+Math.random().toString(36).slice(2);const r=document.createElement('tr');r.className='row';r.onclick=()=>{r.classList.toggle('selected');document.getElementById(id).classList.toggle('open')};r.innerHTML=`<td><span class="badge ${esc(f.statusKey)}">${esc(tr(f.statusKey))}</span></td><td>${esc(tr(f.categoryKey))}</td><td>${esc(tr(f.checkKey))}</td><td>${esc(f.score)} / ${esc(f.maxScore)}</td><td>${esc(textOf(f,'evidence'))}</td><td>${esc(textOf(f,'risk'))}</td><td>${esc(textOf(f,'recommendation'))}</td>`;tbody.appendChild(r);const d=document.createElement('tr');d.id=id;d.className='details';d.innerHTML=`<td colspan="7"><div class="summary"><b>${T.technical}</b></div><div class="pre">${esc((f.details&&f.details.length)?f.details.join('\n'):T.noDetails)}</div></td>`;tbody.appendChild(d)}}function expandAll(){document.querySelectorAll('.details').forEach(x=>x.classList.add('open'))}function collapseAll(){document.querySelectorAll('.details').forEach(x=>x.classList.remove('open'));document.querySelectorAll('.row').forEach(x=>x.classList.remove('selected'))}function downloadJson(){const a=document.createElement('a');a.href=URL.createObjectURL(new Blob([JSON.stringify(data,null,2)],{type:'application/json'}));a.download=`Assessment_${data.computer}_${data.completed}.json`;a.click()}try{init()}catch(e){err.style.display='block';err.textContent=T.renderError+(e&&e.stack?e.stack:e)}</script></body></html>
